sum{j in observed[i, :]}{1 / column_scale[j]}

column_center[j] =
sum{i in observed[:, j]}{
    (1 / row_scale[i]) * (X[i, j]) - row_center[i])
}
------------------------------------------------------------
sum{i in observed[:, j]}{1 / row_scale[i]}

